section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/outsource-pr-etiquette.json",
  "type": "object",
  "title": "Outsource PR Etiquette",
  "required": [
    "pr_id",
    "intent",
    "diff_loc",
    "reviewer",
    "repro_steps",
    "evidence_links",
    "rollback"
  ],
  "additionalProperties": false,
  "properties": {
    "pr_id": {
      "type": "string",
      "minLength": 1,
      "description": "PR identifier (repo#number)."
    },
    "intent": {
      "type": "string",
      "enum": [
        "feature",
        "fix",
        "refactor",
        "chore",
        "docs"
      ],
      "description": "Single intent of the PR."
    },
    "diff_loc": {
      "type": "integer",
      "description": "Changed lines excluding lockfiles."
    },
    "reviewer": {
      "type": "string",
      "minLength": 1,
      "description": "Single primary reviewer handle."
    },
    "repro_steps": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Ordered repro commands."
    },
    "evidence_links": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "URLs to screenshots/logs/payloads."
    },
    "rollback": {
      "type": "string",
      "minLength": 1,
      "description": "One-sentence rollback plan."
    },
    "waiver_reason": {
      "type": [
        "string",
        "null"
      ],
      "description": "If diff_loc>400 this MUST be set."
    }
  }
}
